import { createRouter, createWebHistory } from 'vue-router'
import Home from '../views/Home.vue'
import Configuracion from '@/views/configuracion/Configuracion.vue'
import About from '@/views/About.vue'
import Login from '@/views/login/Login.vue'

import { useAuthStore } from '@/stores/auth' // Asegúrate de tener un store de autenticación

const routes = [
  {
    path: '/',
    name: 'home', 
    component: Home
  },
  {
    path: '/configuracion',
    name: 'ConfiguracionView',
    component: Configuracion
  },
  {
    path: '/about',
    name: 'about',
    component: About
  },  ,
  {
    path: '/login',
    name: 'login',
    component: Login
  },
  {//catch 404
    path: '/:catchAll(.*)',
    name: 'notFound',
    component: About
  }
  //Route Guards
]

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL),
  routes
})

router.beforeEach((to, from, next) => {
  const authStore = useAuthStore();
  const isAuthenticated = authStore.isAuthenticated; // Asume que tienes un getter para esto

  // Si el usuario está autenticado y la ruta a la que va es '/login' o '/register',
  // lo redirigimos a la página de inicio ('/')
  if (isAuthenticated && to.name === 'login') {
    next({ name: 'home' }); // Redirige al usuario al home
  } else {
    // Si no se cumple la condición, permite el acceso
    next();
  }
});

export default router
